    fn drop(&mut self) {
        let inner = self.inner.lock();
        for (fd, file) in inner.fd_table.fd_table.iter().enumerate() {
            if file.is_some() {
                log::info!(
                    "[Process::drop] drop fd {}, file ref cnt {}",
                    fd,
                    Arc::strong_count(&file.as_ref().unwrap().file)
                );
            }
        }
        log::info!("process {} died!", self.pid());
    }
}

