fn create_mem_file(parent_inode: &Arc<dyn Inode>, name: &str) {
    let inode = parent_inode
        .mknod_v(name, InodeMode::FileREG, None)
        .unwrap();
    let file = inode.open(inode.clone()).unwrap();
    file.sync_write(get_app_data_by_name(name).unwrap())
        .unwrap();
}

