            if socket.socket_type().contains(SocketType::SOCK_DGRAM) {
                if socket.loacl_endpoint().eq(&endpoint) {
                    log::info!("[SockTable::can_bind] find port exist");
                    return Some((sockfd, socket));
                }
            }
        }
        None
    }
}

