            }
            IntrSource::SPI2 => {
                // sdcard
                log::info!("receive spi2 intr");
            }
            _ => {
                panic!("unexpected interrupt {}", intr);
            }
        }
        // #[cfg(feature = "board_qemu")]
        // match intr {}
        plic.complete(context_id, intr);
    } else {
        log::info!("didn't claim any intr");
    }
}

