//! Virtual Memory Area (VMA) management for file-backed memory mappings.
//! Provides abstractions for handling memory-mapped files with on-demand loading.

#![no_std]
extern crate alloc;

use alloc::{collections::BTreeSet, vec, vec::Vec};
use axerrno::{LinuxError, LinuxResult};
use memory_addr::{MemoryAddr, VirtAddr, VirtAddrRange};
use page_table_multiarch::PageSize;
use spin::Mutex;

/// Trait for file operations required by VMA management
/// The implementor is responsible for thread safety and sharing semantics
pub trait VmFile: Send + Sync + Clone {
    /// Read data from the file at the specified offset
    fn read_at(&self, buf: &mut [u8], offset: u64) -> LinuxResult<usize>;

    /// Get the length of the file
    fn len(&self) -> LinuxResult<u64>;

    /// Is the file empty?
    fn is_empty(&self) -> LinuxResult<bool> {
        Ok(self.len()? == 0)
    }
}

/// Represents a memory-mapped region with file backing
pub struct MmapRegion<F: VmFile> {
    /// Virtual address range for this mapping
    pub range: VirtAddrRange,
    /// File backing this memory region
    pub file: F,
    /// Offset into the file for this mapping
    pub offset: isize,
    /// Set of populated (loaded) pages in this region
    pub populated: Mutex<BTreeSet<VirtAddr>>,
    /// Page alignment for this mapping
    pub align: PageSize,
}

impl<F: VmFile> MmapRegion<F> {
    /// Create a new memory-mapped region
    pub fn new(range: VirtAddrRange, file: F, offset: isize, align: PageSize) -> Self {
        Self {
            range,
            file,
            offset,
            populated: Mutex::new(BTreeSet::new()),
            align,
        }
    }

    /// Check if a virtual address is contained within this region
    pub fn contains(&self, vaddr: VirtAddr) -> bool {
        self.range.contains(vaddr)
    }

    /// Check if this region overlaps with the given range
    pub fn overlaps(&self, range: &VirtAddrRange) -> bool {
        self.range.overlaps(*range)
    }

    /// Split this region at the given range, returning up to three segments
    /// Returns (before_segment, overlap_segment, after_segment)
    pub fn split_at_range(
        &self,
        range: &VirtAddrRange,
    ) -> (Option<Self>, Option<Self>, Option<Self>) {
        if !self.overlaps(range) {
            return (None, None, None);
        }

        let self_range = &self.range;
        let split_range = range;
        let populated_pages = self.populated.lock().clone();

        // Helper to create a segment with the given range
        let create_segment = |segment_range: VirtAddrRange| -> Self {
            let populated = populated_pages
                .iter()
                .filter(|&page| segment_range.contains(*page))
                .cloned()
                .collect();

            Self {
                range: segment_range,
                file: self.file.clone(),
                offset: self.offset + (segment_range.start - self_range.start) as isize,
                populated: Mutex::new(populated),
                align: self.align,
            }
        };

        // Create segment before the split range
        let before = (self_range.start < split_range.start).then(|| {
            create_segment(VirtAddrRange::from_start_size(
                self_range.start,
                split_range.start - self_range.start,
            ))
        });

        // Create segment after the split range
        let after = (split_range.end < self_range.end).then(|| {
            create_segment(VirtAddrRange::from_start_size(
                split_range.end,
                self_range.end - split_range.end,
            ))
        });

        // Create overlapping segment
        let overlap_start = self_range.start.max(split_range.start);
        let overlap_end = self_range.end.min(split_range.end);
        let overlap = (overlap_start < overlap_end).then(|| {
            create_segment(VirtAddrRange::from_start_size(
                overlap_start,
                overlap_end - overlap_start,
            ))
        });

        (before, overlap, after)
    }

    /// Load data from file into a buffer for the given virtual address
    /// Returns an error if the page is already populated or if file access fails
    pub fn get_buf(&self, vaddr: VirtAddr) -> LinuxResult<Vec<u8>> {
        let page_addr = vaddr.align_down(self.align);
        if self.populated.lock().contains(&page_addr) {
            return Err(LinuxError::EEXIST);
        }

        let page_offset = page_addr - self.range.start;
        let file_offset = self.offset + page_offset as isize;
        if file_offset < 0 || file_offset >= self.file.len()? as isize {
            return Err(LinuxError::EINVAL);
        }

        let buf_size = core::cmp::min(self.align as usize, self.range.end - page_addr);
        let mut buf = vec![0u8; buf_size];
        self.file.read_at(&mut buf, file_offset as u64)?;
        self.populated.lock().insert(page_addr);

        Ok(buf)
    }
}

impl<F: VmFile> Clone for MmapRegion<F> {
    fn clone(&self) -> Self {
        Self {
            range: self.range,
            file: self.file.clone(),
            offset: self.offset,
            populated: Mutex::new(self.populated.lock().clone()),
            align: self.align,
        }
    }
}

/// Manager for Virtual Memory Areas with file backing
#[derive(Clone)]
pub struct VmaManager<F: VmFile> {
    /// Collection of memory-mapped regions
    regions: Vec<MmapRegion<F>>,
}

impl<F: VmFile> Default for VmaManager<F> {
    fn default() -> Self {
        Self::new()
    }
}

impl<F: VmFile> VmaManager<F> {
    /// Create a new VMA manager
    pub fn new() -> Self {
        Self {
            regions: Vec::new(),
        }
    }

    /// Clear all managed regions
    pub fn clear(&mut self) {
        self.regions.clear();
    }

    /// Add a new memory-mapped region to the manager
    pub fn add_region(&mut self, region: MmapRegion<F>) -> LinuxResult<()> {
        self.regions.push(region);
        Ok(())
    }

    /// Find the region containing the given virtual address
    pub fn find_region(&self, vaddr: VirtAddr) -> Option<&MmapRegion<F>> {
        self.regions.iter().find(|r| r.contains(vaddr))
    }

    /// Remove all regions that overlap with the given address range
    /// Splits overlapping regions and retains non-overlapping parts
    pub fn remove_overlapped(&mut self, vaddr_range: VirtAddrRange) -> Vec<MmapRegion<F>> {
        let mut removed = Vec::new();
        let mut retained = Vec::new();

        for region in self.regions.drain(..) {
            if region.overlaps(&vaddr_range) {
                let (before, overlap, after) = region.split_at_range(&vaddr_range);
                if let Some(overlap) = overlap {
                    removed.push(overlap);
                }
                if let Some(before) = before {
                    retained.push(before);
                }
                if let Some(after) = after {
                    retained.push(after);
                }
            } else {
                retained.push(region);
            }
        }
        self.regions = retained;
        removed
    }
}

// ref starry-mix
use core::sync::atomic::Ordering;

use axerrno::{LinuxError, LinuxResult};
use axtask::{TaskExtRef, current};

use xuspace::{UserConstPtr, UserPtr, UserSpaceAccess, nullable};
use xutils::{
    ctypes::{
        FUTEX_CMD_MASK, FUTEX_CMP_REQUEUE, FUTEX_REQUEUE, FUTEX_WAIT, FUTEX_WAIT_BITSET,
        FUTEX_WAKE, FUTEX_WAKE_BITSET, ROBUST_LIST_LIMIT, robust_list, robust_list_head, timespec,
    },
    time::TimeValueLike,
};

use xcore::task::{FutexKey, XProcess, XThread, get_thread, with_uspace, with_xthread};

/// Fast user-space locking system call.
///
/// # Arguments
/// * `uaddr` - Address of the futex variable
/// * `futex_op` - Operation to perform (FUTEX_WAIT, FUTEX_WAKE, etc.)
/// * `value` - Expected value for FUTEX_WAIT or wake count for FUTEX_WAKE
/// * `timeout` - Timeout for FUTEX_WAIT (NULL for infinite)
/// * `uaddr2` - Second futex address for FUTEX_REQUEUE operations
/// * `value3` - Additional value for some operations
pub fn sys_futex(
    uaddr: UserConstPtr<u32>,
    futex_op: u32,
    value: u32,
    timeout: UserConstPtr<timespec>,
    uaddr2: UserPtr<u32>,
    value3: u32,
) -> LinuxResult<isize> {
    debug!("futex {:?} {} {}", uaddr.address(), futex_op, value);

    let xprocess = current().task_ext().xprocess();
    let uspace = xprocess.uspace();
    let futex_table = &xprocess.futex_table;

    let key = FutexKey::new(uaddr.address().as_usize());
    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT | FUTEX_WAIT_BITSET => {
            let uaddr_val = uspace.read(uaddr)?;
            if uaddr_val != value {
                return Err(LinuxError::EAGAIN);
            }
            let timeout = nullable!(uspace.read(timeout))?
                .map(timespec::to_time_value)
                .transpose()?;
            let mut first_call = true;
            let mut mismatches = false;
            let condition = || {
                if first_call {
                    mismatches = uaddr_val != value;
                    first_call = false;
                    mismatches
                } else {
                    true
                }
            };

            let futex = futex_table.get_or_insert(&key);

            if command == FUTEX_WAIT_BITSET {
                with_xthread(|xthread| {
                    xthread.futex_bitset.store(value3, Ordering::SeqCst);
                });
            }

            if let Some(timeout) = timeout {
                if futex.wq.wait_timeout_until(timeout, condition) {
                    return Err(LinuxError::ETIMEDOUT);
                }
            } else {
                futex.wq.wait_until(condition);
            }
            if mismatches {
                return Err(LinuxError::EAGAIN);
            }

            if futex.owner_dead.swap(false, Ordering::SeqCst) {
                Err(LinuxError::EOWNERDEAD)
            } else {
                Ok(0)
            }
        }
        FUTEX_WAKE | FUTEX_WAKE_BITSET => {
            let futex = futex_table.get(&key);
            let mut count = 0;
            if let Some(futex) = futex {
                futex.wq.notify_all_if(false, |_| {
                    if count >= value {
                        false
                    } else {
                        let wake = if command == FUTEX_WAKE_BITSET {
                            let bitset =
                                with_xthread(|xthread| xthread.futex_bitset.load(Ordering::SeqCst));
                            (bitset & value3) != 0
                        } else {
                            true
                        };
                        count += wake as u32;
                        wake
                    }
                });
            }
            axtask::yield_now();
            Ok(count as isize)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if (value as i32) < 0 {
                return Err(LinuxError::EINVAL);
            }

            if command == FUTEX_CMP_REQUEUE && uspace.read(uaddr)? != value3 {
                return Err(LinuxError::EAGAIN);
            }
            let value2 = timeout.address().as_usize() as u32;
            if (value2 as i32) < 0 {
                return Err(LinuxError::EINVAL);
            }

            let futex = futex_table.get(&key);
            let key2 = FutexKey::new(uaddr2.address().as_usize());
            let futex2 = futex_table.get_or_insert(&key2);

            let mut count = 0;
            if let Some(futex) = futex {
                for _ in 0..value {
                    if !futex.wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
                if count == value as isize {
                    count += futex.wq.requeue(value2 as usize, &futex2.wq) as isize;
                }
            }
            Ok(count)
        }
        _ => Err(LinuxError::ENOSYS),
    }
}

/// Get robust futex list head for a thread.
///
/// # Arguments
/// * `tid` - Thread ID (0 for calling thread)
/// * `head` - Buffer to store robust list head pointer
/// * `size` - Buffer to store robust list head size
pub fn sys_get_robust_list(
    tid: u32,
    head: UserPtr<UserConstPtr<robust_list_head>>,
    size: UserPtr<usize>,
) -> LinuxResult<isize> {
    let thr = get_thread(tid)?;
    let xthread = XThread::from_thread(&thr);
    let uspace = XProcess::from_thread(&thr).uspace();
    uspace.write(head, xthread.robust_list_head.load(Ordering::SeqCst).into())?;
    uspace.write(size, size_of::<robust_list_head>())?;

    Ok(0)
}

/// Set robust futex list head for the calling thread.
///
/// # Arguments
/// * `head` - Robust list head pointer
/// * `size` - Size of the robust list head structure
pub fn sys_set_robust_list(
    head: UserConstPtr<robust_list_head>,
    size: usize,
) -> LinuxResult<isize> {
    if size != size_of::<robust_list_head>() {
        return Err(LinuxError::EINVAL);
    }
    with_xthread(|xthread| {
        xthread
            .robust_list_head
            .store(head.address().as_usize(), Ordering::SeqCst);
    });

    Ok(0)
}

fn handle_futex_death(entry: *mut robust_list, offset: i64) -> LinuxResult<()> {
    let address = (entry as u64)
        .checked_add_signed(offset)
        .ok_or(LinuxError::EINVAL)?;
    let address: usize = address.try_into().map_err(|_| LinuxError::EINVAL)?;

    let futex_table = &current().task_ext().xprocess().futex_table;

    let Some(futex) = futex_table.get(&FutexKey::new(address)) else {
        return Ok(());
    };
    futex.owner_dead.store(true, Ordering::SeqCst);
    futex.wq.notify_one(false);
    Ok(())
}

pub fn exit_robust_list(head: &mut robust_list_head) -> LinuxResult<()> {
    let mut limit = ROBUST_LIST_LIMIT;

    let mut entry = head.list.next;
    let offset = head.futex_offset;
    let pending = head.list_op_pending;

    with_uspace(|uspace| {
        while !core::ptr::eq(entry, &head.list) {
            let next_entry = uspace.read(UserPtr::from(entry))?.next;
            if entry != pending {
                handle_futex_death(entry, offset)?;
            }
            entry = next_entry;

            limit -= 1;
            if limit == 0 {
                return Err(LinuxError::ELOOP);
            }
            axtask::yield_now();
        }
        Ok(())
    })
}

//! Architecture-dependent constants for the kernel/user address layout.
//!
//! Most addresses are shared across all supported architectures; only the
//! width of the user address space (and therefore the stack top) and the
//! per-arch user stack size differ.

cfg_if::cfg_if! {
    if #[cfg(target_arch = "riscv64")] {
        // Sv39 user space: 38-bit addressable region.
        pub const USER_SPACE_SIZE: usize = 0x3f_ffff_f000;
        pub const USER_STACK_TOP: usize = 0x4_0000_0000;
        // RISC-V musl libc binaries push noticeably more onto the stack than
        // the LoongArch ones, so give them a bit more headroom.
        pub const USER_STACK_SIZE: usize = 0x8_0000;
    } else if #[cfg(target_arch = "loongarch64")] {
        pub const USER_SPACE_SIZE: usize = 0x3f_ffff_f000;
        pub const USER_STACK_TOP: usize = 0x4_0000_0000;
        pub const USER_STACK_SIZE: usize = 0x5_0000;
    } else {
        compile_error!("unsupported target architecture for xcore::config");
    }
}

/// Lowest user-space virtual address actually used for code/data.
pub const USER_SPACE_BASE: usize = 0x1000;
/// Base address used when loading a dynamic ELF interpreter (ld.so).
pub const USER_INTERP_BASE: usize = 0x400_0000;

/// Lowest user-space heap address; `brk` grows up from here.
pub const USER_HEAP_BASE: usize = 0x4000_0000;
/// Initial size of the user heap.
pub const USER_HEAP_SIZE: usize = 0x1_0000;

/// Per-thread kernel stack size.
pub const KERNEL_STACK_SIZE: usize = 0x40000;

/// vDSO code-page base virtual address (R-X to user, alloc-backed,
/// per-process copy of the embedded ELF blob).
///
/// Reuses the slot freed by removing the legacy `SIGNAL_TRAMPOLINE` page;
/// `__vdso_rt_sigreturn` lives inside the same image now.
pub const USER_VDSO_BASE: usize = 0x4001_0000;

/// vDSO data-page virtual address (R-only to user, single shared phys
/// page across all processes; see `xcore::vdso::data::VDSO_DATA`).
pub const USER_VDSO_DATA: usize = 0x4001_2000;

