pub struct CowPageManager {
    pub page_mgr: SyncUnsafeCell<PageManager>,
    page_fault_handler: Arc<dyn PageFaultHandler>,
}

impl CowPageManager {
    pub fn new() -> Self {
        Self {
            page_mgr: SyncUnsafeCell::new(PageManager::new()),
            page_fault_handler: CowPageFaultHandler {}.arc_clone(),
        }
    }

    pub fn from_another(another: &Self, page_table: Arc<SyncUnsafeCell<PageTable>>) -> Self {
        // TODO: optimize: only need to map the leaf page
        let page_mgr = SyncUnsafeCell::new(another.page_mgr.get_unchecked_mut().clone());
        for (vpn, page) in another.page_mgr.get_unchecked_mut().0.iter() {
            log::trace!(
                "[CowPageManager::from_another]: map vpn {:#x}, ppn {:#x}, map perm {:?}",
                vpn.0,
                page.data_frame.ppn.0,
                *page.permission.lock()
            );
            let mut pte_flags: PTEFlags = (*page.permission.lock()).into();
            pte_flags |= PTEFlags::COW | PTEFlags::U;
            pte_flags.remove(PTEFlags::W);
            page_table
                .get_unchecked_mut()
                .map(*vpn, page.data_frame.ppn, pte_flags);
        }
        // page_table.get_unchecked_mut().activate();
        Self {
            page_mgr,
            page_fault_handler: another.page_fault_handler.arc_clone(),
        }
    }

    pub fn page_fault_handler(
        &self,
        _va: VirtAddr,
    ) -> GeneralRet<(Arc<dyn PageFaultHandler>, Option<&VmArea>)> {
        Ok((self.page_fault_handler.clone(), None))
    }

    #[allow(unused)]
    pub fn clear(&mut self) {
        self.page_mgr.get_mut().0.clear()
    }
}

use crate::sync::mutex::SpinNoIrqLock;
use alloc::collections::VecDeque;
use async_task::{Runnable, ScheduleInfo, Task, WithInfo};
use core::future::Future;

struct TaskQueue {
    queue: SpinNoIrqLock<Option<VecDeque<Runnable>>>,
}

impl TaskQueue {
    pub const fn new() -> Self {
        Self {
            queue: SpinNoIrqLock::new(None),
        }
    }
    pub fn init(&self) {
        *self.queue.lock() = Some(VecDeque::new());
    }
    pub fn push(&self, runnable: Runnable) {
        // log::error!("push lock before");
        let mut lock = self.queue.lock();
        // log::error!("push before, queue len {}", lock.as_mut().unwrap().len());
        lock.as_mut().unwrap().push_back(runnable);
        // self.queue.lock().as_mut().unwrap().push_back(runnable);
        // log::error!("push after");
    }
    pub fn push_preempt(&self, runnable: Runnable) {
        self.queue.lock().as_mut().unwrap().push_front(runnable);
    }
    pub fn fetch(&self) -> Option<Runnable> {
        self.queue.lock().as_mut().unwrap().pop_front()
    }
}

static TASK_QUEUE: TaskQueue = TaskQueue::new();

pub fn init() {
    TASK_QUEUE.init();
}

/// Add a task into task queue
pub fn spawn<F>(future: F) -> (Runnable, Task<F::Output>)
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    let schedule = move |runnable: Runnable, info: ScheduleInfo| {
        // TASK_QUEUE.push(runnable);
        if info.woken_while_running {
            // i.e `yield_now()`
            // log::error!("yield now");
            TASK_QUEUE.push(runnable);
        } else {
            // i.e. woken up by some signal
            TASK_QUEUE.push_preempt(runnable);
        }
    };
    async_task::spawn(future, WithInfo(schedule))
}

/// Return the number of the tasks executed
pub fn run_until_idle() -> usize {
    let mut n = 0;
    loop {
        if let Some(task) = TASK_QUEUE.fetch() {
            // info!("fetch a task");
            task.run();
            n += 1;
        } else {
            break;
        }
    }
    n
}

#[allow(unused)]
pub fn run_forever() -> ! {
    loop {
        if let Some(task) = TASK_QUEUE.fetch() {
            task.run();
        }
    }
}

